+    fn test_goaway_received_with_error() {
+        let mut conn = Connection::client(Settings::client());
+        conn.state = ConnectionState::Open;
+
+        let goaway = Frame::GoAway(GoAwayFrame::new(0, ErrorCode::InternalError));
